import yaml
from pathlib import Path
from control_model import Control, FrameworkMapping
from datetime import date

LIBRARY_PATH = Path("governance/control_library.yaml")

def load_controls() -> list[Control]:
    data = yaml.safe_load(LIBRARY_PATH.read_text())
    controls = []
    for item in data["controls"]:
        mappings = [
            FrameworkMapping(**m) for m in item.pop("framework_mappings", [])
        ]
        item["last_reviewed"] = date.fromisoformat(item["last_reviewed"])
        controls.append(Control(**item, framework_mappings=mappings))
    return controls


def controls_for_requirement(
    controls: list[Control],
    framework: str,
    requirement_id: str,
) -> list[Control]:
    """Return all controls that satisfy a specific framework requirement."""
    return [
        c for c in controls
        if any(
            m.framework == framework and m.requirement_id == requirement_id
            for m in c.framework_mappings
        )
    ]


def coverage_report(controls: list[Control]) -> dict:
    """
    For each framework, report implemented vs partial vs planned control counts.
    """
    from collections import defaultdict, Counter
    report = defaultdict(lambda: Counter())
    for c in controls:
        for fw in c.frameworks_covered():
            report[fw][c.implementation_status] += 1
    return dict(report)

import json
from datetime import date

def generate_evidence_package(
    controls: list[Control],
    framework: str,
    output_path: str,
) -> None:
    """
    Produce a JSON evidence package for a specific framework.
    Groups controls by requirement_id and includes evidence locations.
    """
    # Collect all requirement IDs for this framework
    req_map: dict[str, list[dict]] = {}

    for ctrl in controls:
        for mapping in ctrl.framework_mappings:
            if mapping.framework != framework:
                continue
            if mapping.requirement_id not in req_map:
                req_map[mapping.requirement_id] = {
                    "requirement_id": mapping.requirement_id,
                    "requirement_title": mapping.requirement_title,
                    "satisfying_controls": [],
                }
            req_map[mapping.requirement_id]["satisfying_controls"].append({
                "control_id": ctrl.control_id,
                "title": ctrl.title,
                "status": ctrl.implementation_status,
                "evidence_type": ctrl.evidence_type,
                "evidence_location": ctrl.evidence_location,
                "owner": ctrl.owner,
                "last_reviewed": str(ctrl.last_reviewed),
                "overdue": ctrl.is_overdue_review(),
            })

    package = {
        "framework": framework,
        "generated_at": str(date.today()),
        "requirements": sorted(req_map.values(), key=lambda r: r["requirement_id"]),
        "gaps": [
            rid for rid, req in req_map.items()
            if all(c["status"] != "implemented" for c in req["satisfying_controls"])
        ],
    }

    with open(output_path, "w") as f:
        json.dump(package, f, indent=2)

    print(f"Evidence package for {framework}: {len(req_map)} requirements, "
          f"{len(package['gaps'])} gaps")
